interface TreeNode {
  f?: number;
  t?: number;
  l?: number;
  r?: number;
  v?: number;
}

interface ModelData {
  featureNames: string[];
  scalerMean: number[];
  scalerStd: number[];
  trees: TreeNode[][];
  metrics: Record<string, number>;
  confusion: Record<string, number>;
  trainSize: number;
  testSize: number;
  hyperparameters: Record<string, string>;
}

function traverseTree(tree: TreeNode[], features: number[]): number {
  let nodeIdx = 0;
  while (nodeIdx < tree.length) {
    const node = tree[nodeIdx];
    if (node.v !== undefined) {
      return node.v;
    }
    if (node.f === undefined || node.t === undefined || node.l === undefined || node.r === undefined) {
      return 0.5;
    }
    nodeIdx = features[node.f] <= node.t ? node.l : node.r;
  }
  return 0.5;
}

function predict(disease: string, features: Record<string, number>): {
  prediction: "positive" | "negative";
  probability: number;
  confidence: string;
} {
  const model = (modelsData as Record<string, ModelData>)[disease];
  if (!model) throw new Error(`Unknown disease: ${disease}`);

  const values = model.featureNames.map((name: string) => {
    const val = features[name];
    if (val === undefined || val === null) throw new Error(`Missing feature: ${name}`);
    return Number(val);
  });

  // Standardize features
  const scaled = values.map((v: number, i: number) => (v - model.scalerMean[i]) / model.scalerStd[i]);

  // Aggregate predictions from all trees (Random Forest voting)
  const treePredictions = model.trees.map((tree: TreeNode[]) => traverseTree(tree, scaled));
  const probability = treePredictions.reduce((sum: number, p: number) => sum + p, 0) / treePredictions.length;

  const prediction = probability > 0.5 ? "positive" : "negative";
  const confidence = probability > 0.75 || probability < 0.25 ? "high" : probability > 0.6 || probability < 0.4 ? "moderate" : "low";

  return {
    prediction,
    probability: Math.round(probability * 1000) / 1000,
    confidence,
  };
}

serve(async (req) => {
  if (req.method === "OPTIONS") {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const { disease, features } = await req.json();

    if (!disease || !features) {
      return new Response(
        JSON.stringify({ error: "Missing 'disease' or 'features' in request body" }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const validDiseases = ["diabetes", "heart", "kidney", "liver"];
    if (!validDiseases.includes(disease)) {
      return new Response(
        JSON.stringify({ error: `Invalid disease. Must be one of: ${validDiseases.join(", ")}` }),
        { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    const result = predict(disease, features);

    return new Response(
      JSON.stringify({
        disease,
        algorithm: "Random Forest Classifier",
        ...result,
        disclaimer: "This is a demo prediction based on synthetic training data — not a real medical diagnosis.",
      }),
      { headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  } catch (error) {
    return new Response(
      JSON.stringify({ error: error.message }),
      { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});
